import{_ as e,o as t,c as o,ag as c}from"./chunks/framework.CTpQozEL.js";const b=JSON.parse('{"title":"WebChat (macOS)","description":"mac 앱이 게이트웨이 WebChat을 임베딩하는 방법 및 디버깅 방법","frontmatter":{"title":"WebChat (macOS)","description":"mac 앱이 게이트웨이 WebChat을 임베딩하는 방법 및 디버깅 방법"},"headers":[],"relativePath":"platforms/mac/webchat.md","filePath":"platforms/mac/webchat.md","lastUpdated":null}'),l={name:"platforms/mac/webchat.md"};function i(d,a,s,n,h,r){return t(),o("div",null,[...a[0]||(a[0]=[c('<h1 id="webchat-macos-앱" tabindex="-1">WebChat (macOS 앱) <a class="header-anchor" href="#webchat-macos-앱" aria-label="Permalink to &quot;WebChat (macOS 앱)&quot;">​</a></h1><p>macOS 메뉴 바 앱은 WebChat UI를 네이티브 SwiftUI 뷰로 임베딩합니다. 게이트웨이에 연결하고 선택된 에이전트의 <strong>main 세션</strong>을 기본으로 합니다 (다른 세션을 위한 세션 스위처 포함).</p><ul><li><strong>로컬 모드</strong>: 로컬 게이트웨이 WebSocket에 직접 연결합니다.</li><li><strong>원격 모드</strong>: SSH를 통해 게이트웨이 제어 포트를 전달하고 해당 터널을 데이터 플레인으로 사용합니다.</li></ul><h2 id="시작-및-디버깅" tabindex="-1">시작 및 디버깅 <a class="header-anchor" href="#시작-및-디버깅" aria-label="Permalink to &quot;시작 및 디버깅&quot;">​</a></h2><ul><li><p>수동: Lobster 메뉴 → &quot;Open Chat&quot;.</p></li><li><p>테스트를 위한 자동 열기:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dist/OpenClaw.app/Contents/MacOS/OpenClaw</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --webchat</span></span></code></pre></div></li><li><p>로그: <code>./scripts/clawlog.sh</code> (서브시스템 <code>ai.openclaw</code>, 카테고리 <code>WebChatSwiftUI</code>).</p></li></ul><h2 id="연결-방식" tabindex="-1">연결 방식 <a class="header-anchor" href="#연결-방식" aria-label="Permalink to &quot;연결 방식&quot;">​</a></h2><ul><li>데이터 플레인: 게이트웨이 WS 메서드 <code>chat.history</code>, <code>chat.send</code>, <code>chat.abort</code>, <code>chat.inject</code> 및 이벤트 <code>chat</code>, <code>agent</code>, <code>presence</code>, <code>tick</code>, <code>health</code>.</li><li><code>chat.history</code>는 표시 정규화된 전사 행을 반환합니다. 인라인 지시어 태그는 표시 텍스트에서 제거되고, 일반 텍스트 도구 호출 XML 페이로드 (<code>&lt;tool_call&gt;...&lt;/tool_call&gt;</code>, <code>&lt;function_call&gt;...&lt;/function_call&gt;</code>, <code>&lt;tool_calls&gt;...&lt;/tool_calls&gt;</code>, <code>&lt;function_calls&gt;...&lt;/function_calls&gt;</code> 포함) 및 잘린 도구 호출 블록과 누출된 ASCII/전각 모델 제어 토큰은 제거되며, 정확히 <code>NO_REPLY</code> / <code>no_reply</code>인 순수 무음 토큰 어시스턴트 행은 생략되고, 크기가 큰 행은 플레이스홀더로 교체될 수 있습니다.</li><li>세션: 기본값은 기본 세션 (<code>main</code>, 또는 범위가 전역인 경우 <code>global</code>). UI는 세션 간에 전환할 수 있습니다.</li><li>온보딩은 최초 실행 설정을 별도로 유지하기 위해 전용 세션을 사용합니다.</li></ul><h2 id="보안-표면" tabindex="-1">보안 표면 <a class="header-anchor" href="#보안-표면" aria-label="Permalink to &quot;보안 표면&quot;">​</a></h2><ul><li>원격 모드는 SSH를 통해 게이트웨이 WebSocket 제어 포트만 전달합니다.</li></ul><h2 id="알려진-제한-사항" tabindex="-1">알려진 제한 사항 <a class="header-anchor" href="#알려진-제한-사항" aria-label="Permalink to &quot;알려진 제한 사항&quot;">​</a></h2><ul><li>UI는 채팅 세션에 최적화되어 있습니다 (전체 브라우저 샌드박스 아님).</li></ul>',11)])])}const u=e(l,[["render",i]]);export{b as __pageData,u as default};
